// src/components/DocTypeSelector.tsx
"use client";

import { useState } from "react";
import { clsx } from "clsx";
import { FileText, Receipt, BookOpen, Scale, Landmark } from "lucide-react";

const docTypes = [
  { id: "invoice", label: "請求書・領収書", icon: Receipt },
  { id: "bank", label: "預金通帳", icon: Landmark },
  { id: "pl", label: "試算表(TB)", icon: Scale },
  { id: "gl", label: "総勘定元帳", icon: BookOpen },
  { id: "tax", label: "申告書・決算書", icon: FileText },
];

export default function DocTypeSelector() {
  const [activeType, setActiveType] = useState("gl");

  return (
    <div className="h-24 bg-slate-900 border-b border-slate-700 relative flex items-center shadow-lg z-10">
      {/* グラデーションマスク */}
      <div className="absolute inset-y-0 left-0 w-32 mask-h-left z-10 pointer-events-none" />
      <div className="absolute inset-y-0 right-0 w-32 mask-h-right z-10 pointer-events-none" />

      {/* 横スクロールコンテナ */}
      <div className="h-drum-scroller no-scrollbar w-full px-[50vw]">
        {docTypes.map((doc) => {
          const Icon = doc.icon;
          const isActive = activeType === doc.id;
          return (
            <div
              key={doc.id}
              onClick={() => setActiveType(doc.id)}
              className={clsx(
                "h-item group flex flex-col items-center justify-center gap-2 transition-all duration-300",
                isActive ? "active text-blue-400" : "text-slate-500"
              )}
            >
              <div className={clsx(
                "p-3 rounded-full transition-all duration-300",
                isActive ? "bg-blue-500/20 ring-2 ring-blue-500" : "bg-slate-800"
              )}>
                <Icon size={24} />
              </div>
              <span className="text-sm font-bold tracking-wider">{doc.label}</span>
              
              {/* アクティブ時の光るバー */}
              {isActive && (
                <div className="absolute bottom-0 h-1 w-16 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.8)] rounded-t-full" />
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}